import { useEffect, useState } from "react";
import { useNavigate } from "react-router-dom";
import {
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
} from "@/components/ui/dialog";
import { useXiaoxiongChat, Provider } from "@/hooks/useXiaoxiongChat";
import XiaoxiongChatContent from "@/components/XiaoxiongChatContent";
import { useSiteSettings } from "@/hooks/useSiteSettings";
import { useTranslation } from "react-i18next";
import { useIsMobile } from "@/hooks/use-mobile";

import { SquarePen } from "lucide-react";


interface AskXiaoxiongDialogProps {
  open: boolean;
  onOpenChange: (open: boolean) => void;
}

const AskXiaoxiongDialog = ({ open, onOpenChange }: AskXiaoxiongDialogProps) => {
  const { i18n, t } = useTranslation();
  const navigate = useNavigate();
  const isMobile = useIsMobile();
  const { settings } = useSiteSettings();
  const logoUrl = settings?.logo_url;
  
  // Use provider from site settings, fallback to xiaoxiong-community (consistent with AskXiaoxiong page)
  const provider = (settings?.ai_provider || "xiaoxiong-community") as Provider;
  
  const {
    input,
    setInput,
    messages,
    isLoading,
    isLoadingHistory,
    showLocationDialog,
    setShowLocationDialog,
    pendingMessage,
    setPendingMessage,
    handleSubmit,
    handleKeyDown,
    handleLocationConfirm,
    processMessage,
    abortRequest,
    requestLocation,
    clearChat,
    recipeImages,
  } = useXiaoxiongChat(provider);

  // On mobile, redirect to full page instead of dialog
  useEffect(() => {
    if (open && isMobile) {
      onOpenChange(false);
      navigate("/ask-xiaoxiong");
    }
  }, [open, isMobile, navigate, onOpenChange]);

  // Request location on dialog open
  useEffect(() => {
    if (open && !isMobile) {
      requestLocation();
    }
  }, [open, isMobile, requestLocation]);

  // Cleanup on close
  const handleClose = () => {
    abortRequest();
    onOpenChange(false);
  };

  const handleClearAndNewChat = () => {
    const confirmed = window.confirm(t("aiRecipe.newChatConfirm", "开始新对话将清除当前聊天记录，确定吗？"));
    if (!confirmed) return;

    try {
      void Promise.resolve(clearChat()).catch((error) => {
        console.error("Clear chat failed:", error);
      });
    } catch (error) {
      console.error("Clear chat failed:", error);
    }
  };

  const getTitle = () => {
    const titles: Record<string, string> = {
      zh: "小熊AI助手",
      en: "Xiaoxiong AI Assistant",
      pt: "Assistente IA Xiaoxiong",
      es: "Asistente IA Xiaoxiong",
      fr: "Assistant IA Xiaoxiong",
      de: "Xiaoxiong KI-Assistent",
      it: "Assistente IA Xiaoxiong",
      ja: "小熊AIアシスタント",
      ko: "샤오슝 AI 어시스턴트",
      ar: "مساعد شاوشيونغ الذكي",
      ru: "ИИ-ассистент Сяосюн",
    };
    return titles[i18n.language] || titles.en;
  };

  // Don't render dialog on mobile (will redirect to page)
  if (isMobile) {
    return null;
  }

  return (
    <Dialog open={open} onOpenChange={handleClose}>
      <DialogContent className="sm:max-w-2xl sm:h-[90vh] sm:max-h-[90vh] flex flex-col p-0 gap-0 overflow-hidden">
        <DialogHeader className="px-4 py-3 shrink-0 border-b">
          <div className="flex items-center justify-between pr-8">
            <DialogTitle className="text-base font-semibold flex items-center gap-2">
              {logoUrl && <img src={logoUrl} alt="Logo" className="w-8 h-8 rounded-full object-cover" />}
              {getTitle()}
            </DialogTitle>
            {messages.length > 0 && (
              <button
                onClick={handleClearAndNewChat}
                className="p-1 hover:bg-muted rounded-md text-muted-foreground hover:text-primary transition-colors"
                title={t("aiRecipe.newChat", "新对话")}
              >
                <SquarePen className="h-4 w-4" />
              </button>
            )}
          </div>
        </DialogHeader>

        <div className="flex-1 min-h-0 flex flex-col overflow-hidden">
          <XiaoxiongChatContent
            messages={messages}
            input={input}
            setInput={setInput}
            isLoading={isLoading}
            isLoadingHistory={isLoadingHistory}
            showLocationDialog={showLocationDialog}
            setShowLocationDialog={setShowLocationDialog}
            pendingMessage={pendingMessage}
            handleSubmit={handleSubmit}
            handleKeyDown={handleKeyDown}
            handleLocationConfirm={handleLocationConfirm}
            processMessage={processMessage}
            setPendingMessage={setPendingMessage}
            onClose={handleClose}
            onClearChat={clearChat}
            showBackButton={false}
            showHeader={false}
            className="flex-1"
            recipeImages={recipeImages}
          />
        </div>
      </DialogContent>

    </Dialog>
  );
};

export default AskXiaoxiongDialog;
